int sos_start_kernel()
{
    // if ( hsai::get_cpu()->get_cpu_id() == 0 )
    // 初始化输出串口
    chardev_init();
    printfinit();
    for (int i = 65; i < 65 + 26; i++)
    {
        put_char_sync(i);
        put_char_sync('t');
    }
    put_char_sync('\n');
    printf_figlet_color("SOS Is Booting!"); //< 艺术字打印
    LOG("sos_start_kernel at :%p\n", &sos_start_kernel);
    extern uint64 boot_time;
    LOG("System boot timestamp is: %lld\n", boot_time);
    // 初始化线程和进程
    thread_init();
    proc_init();
    // 初始化物理内存
    pmem_init();
    vmem_init();
    slab_init();
    // 初始化中断和异常
    hsai_trap_init();
    // 初始化磁盘设备。本来想把这个提取到hsai的，但是发现那么做会使la运行速度变慢，先这样
#if defined RISCV
    plicinit();
    plicinithart();
    virtio_disk_init();
#else 
    virtio_probe();//发现virtio-blk-pci设备
    la_virtio_disk_init();
#endif
    // 初始化文件系统
    init_fs();
    binit();
    fileinit();
    inodeinit();
    vfs_ext4_init();
    // 初始化init线程
    init_process();
    // 进入调度器
    scheduler();
    while (1)
        return 0;
}

