void vmem_init()
{
    kernel_pagetable = pmem_alloc_pages(1); ///< 分配一个页,存放内核页表 分配时已清空页面
    LOG("kernel_pagetable address: %p\n", kernel_pagetable);
    // RISCV需要将内核映射到外部，LA由于映射窗口，不需要映射
#if defined RISCV
