int get_order(uint64 size)
{
    int order = 0;
    uint64 temp = 1;

    while (temp < size && order < BUDDY_MAX_ORDER)
    {
        temp <<= 1;
        order++;
    }

    // 确保不会超过最大阶数
    if (order >= BUDDY_MAX_ORDER)
    {
        DEBUG_LOG_LEVEL(LOG_DEBUG,"get_order: size %lu too large, max order %d\n",
               size, BUDDY_MAX_ORDER);
        order = -1;
    }

    return order;
}

