}

static int
oom_adj_from_score_adj(int score_adj)
{
    if (score_adj <= -1000)
        return -17;
    if (score_adj >= 1000)
        return 15;
    if (score_adj < 0)
        return -(((-score_adj) * 17 + 999) / 1000);
    return (score_adj * 15) / 1000;
}

static int
score_adj_from_oom_adj(int oom_adj)
{
    if (oom_adj <= -17)
        return -1000;
    if (oom_adj >= 15)
        return 1000;
    if (oom_adj < 0)
        return -(((-oom_adj) * 1000) / 17);
    return (oom_adj * 1000) / 15;
}

