    tv.sec = boot_time + clocks_to_sec(clk);
    tv.usec = clocks_to_usec_rem(clk);
    return tv;
}
timespec_t timer_get_ntime() {
    timespec_t ts;
    uint64 clk = r_time();

    ts.tv_sec = boot_time + clocks_to_sec(clk);
    ts.tv_nsec = clocks_to_nsec_rem(clk);

    return ts;
}

